import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;
import java.lang.reflect.Modifier;

public class CSVFormatTest {

    private Object setFinalField(Object target, String fieldName, Object value) throws Exception {
        Field field = CSVFormat.class.getDeclaredField(fieldName);
        field.setAccessible(true);

        // Remove final modifier
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(field, field.getModifiers() & ~Modifier.FINAL);

        field.set(target, value);
        return target;
    }

    @Test
    void testIsQuoteCharacterSet_whenQuoteCharacterIsSet() throws Exception {
        CSVFormat format = new CSVFormat(',', '\"', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);

        // Using reflection to set private final field quoteCharacter
        setFinalField(format, "quoteCharacter", '\"');

        // invoke isQuoteCharacterSet
        boolean result = format.isQuoteCharacterSet();
        assertTrue(result);
    }

    @Test
    void testIsQuoteCharacterSet_whenQuoteCharacterIsNull() throws Exception {
        CSVFormat format = new CSVFormat(',', null, null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);

        // Using reflection to set private final field quoteCharacter to null
        setFinalField(format, "quoteCharacter", null);

        // invoke isQuoteCharacterSet
        boolean result = format.isQuoteCharacterSet();
        assertFalse(result);
    }
}
